import java.util.*;

public class Solution {

    // Helper class to represent a 3D point and ensure proper hashing and equality checking.
    private static class Point {
        long x, y, z;

        public Point(long x, long y, long z) {
            this.x = x;
            this.y = y;
            this.z = z;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Point point = (Point) o;
            return x == point.x && y == point.y && z == point.z;
        }

        @Override
        public int hashCode() {
            // Simple hash combining three longs
            return Objects.hash(x, y, z);
        }
    }

    public static long solve(long[][] points, long[] target) {
        Point targetPoint = new Point(target[0], target[1], target[2]);

        // 1. Initialize S_0 (CurrentSet) and check k=0
        Set<Point> currentSet = new HashSet<>();
        for (long[] p : points) {
            Point pPoint = new Point(p[0], p[1], p[2]);
            if (currentSet.add(pPoint)) {
                // Point successfully added (handles potential duplicates in input, though prompt says none)
                if (pPoint.equals(targetPoint)) {
                    return 0;
                }
            }
        }

        // If only one point exists, no new pairs can be formed.
        if (currentSet.size() < 2) {
            return -1;
        }

        // 2. Iterative generation (k = 1, 2, 3, ...)
        int k = 0;
        while (true) {
            k++;

            // List representation of currentSet for easy indexed iteration
            List<Point> currentPointsList = new ArrayList<>(currentSet);
            int N = currentPointsList.size();

            // Set to store all generated points C_k in this step
            Set<Point> generatedCandidates = new HashSet<>();

            // Generate all pairs (a, b) where a != b
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    Point a = currentPointsList.get(i);
                    Point b = currentPointsList.get(j);

                    // Calculate midpoint c = [floor((x1 + x2) / 2), ...]
                    // Since coordinates are non-negative, integer division naturally performs floor operation.
                    long cx = (a.x + b.x) / 2;
                    long cy = (a.y + b.y) / 2;
                    long cz = (a.z + b.z) / 2;

                    Point c = new Point(cx, cy, cz);
                    generatedCandidates.add(c);
                }
            }

            // A_k: Points newly generated in this step (C_k \ S_{k-1})
            Set<Point> newlyAddedPoints = new HashSet<>();
            boolean foundNewPoint = false;

            for (Point c : generatedCandidates) {
                if (!currentSet.contains(c)) {
                    newlyAddedPoints.add(c);

                    // Check if the target was newly generated
                    if (c.equals(targetPoint)) {
                        return k;
                    }
                    foundNewPoint = true;
                }
            }

            // Update S_k = S_{k-1} U A_k
            currentSet.addAll(newlyAddedPoints);

            // Termination condition: If no new points were generated, we stop.
            if (!foundNewPoint) {
                return -1;
            }

            // Safety break (though theoretically unnecessary given bounded state space)
            if (k > 1000) { 
                return -1;
            }
        }
    }
