class Point {
    long x, y, z;

    public Point(long x, long y, long z) {
        this.x = x;
        this.y = y;
        this.z = z;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Point point = (Point) o;
        return x == point.x && y == point.y && z == point.z;
    }

    @Override
    public int hashCode() {
        // Simple hashing suitable for small coordinate range
        // Since coordinates are <= 6, we can use a base larger than 6 (e.g., 8)
        int result = 1;
        result = 31 * result + (int) (x % 8);
        result = 31 * result + (int) (y % 8);
        result = 31 * result + (int) (z % 8);
        return result;
    }
}

public class Solution {
    public static long solve(long[][] points, long[] target) {

        Set<Point> currentPoints = new HashSet<>();
        for (long[] p : points) {
            currentPoints.add(new Point(p[0], p[1], p[2]));
        }

        Point targetPoint = new Point(target[0], target[1], target[2]);

        // Check Generation 0
        if (currentPoints.contains(targetPoint)) {
            return 0;
        }

        long k = 0;

        // Simulation loop
        while (true) {
            k++;

            // Convert Set to List to allow indexed iteration for pairs
            List<Point> P_list = new ArrayList<>(currentPoints);
            int N = P_list.size();

            if (N < 2) {
                // Cannot generate any new points
                return -1;
            }

            Set<Point> nextPoints = new HashSet<>();

            // Generate all unique pairs (a, b) where a != b (coordinate-wise)
            // Since we iterate over unique points stored in the set, and i != j, 
            // the points must be coordinate-wise different.
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    Point a = P_list.get(i);
                    Point b = P_list.get(j);

                    // Calculate c = floor((a+b)/2)
                    long cx = (a.x + b.x) / 2; // Integer division acts as floor for non-negative numbers
                    long cy = (a.y + b.y) / 2;
                    long cz = (a.z + b.z) / 2;

                    nextPoints.add(new Point(cx, cy, cz));
                }
            }

            if (nextPoints.isEmpty()) {
                // If we generated 0 points, we are stuck (should only happen if N < 2, handled above)
                // but acts as a safety break if N >= 2 but all pairs somehow resulted in no new points, 
                // although this is impossible if N >= 2.
                return -1;
            }

            // Check if we actually generated new, unique points
            boolean genuinelyNew = false;
            for (Point p : nextPoints) {
                if (!currentPoints.contains(p)) {
                    genuinelyNew = true;
                    break;
                }
            }

            // Update the set of available points
            currentPoints.addAll(nextPoints);

            // If no genuinely new points were added, and the target wasn't found, we are stuck.
            if (!genuinelyNew) {
                return -1;
            }

            // Check for target presence in the expanded set (Generation k)
            if (currentPoints.contains(targetPoint)) {
                return k;
            }
        }
